-- Auto-generated by pg_pack (ops, ops_ut)
-- 2026-03-13

-- Schema: ops
CREATE SCHEMA IF NOT EXISTS ops;

CREATE OR REPLACE FUNCTION ops._module_list()
 RETURNS TABLE(module text)
 LANGUAGE sql
 STABLE
AS $function$
  SELECT n.nspname::text AS module
    FROM pg_namespace n
    JOIN pg_proc p ON p.pronamespace = n.oid AND p.proname = 'nav_items'
   WHERE n.nspname NOT IN ('pgv', 'ops')
     AND n.nspname NOT LIKE '%\_qa' ESCAPE '\'
   ORDER BY n.nspname;
$function$;
COMMENT ON FUNCTION ops._module_list() IS 'Liste des modules connus via pg_namespace (schemas ayant nav_items, hors QA)';

CREATE OR REPLACE FUNCTION ops._module_stats(p_module text)
 RETURNS TABLE(func_count integer, test_count integer, msg_new integer, msg_total integer, hook_deny integer, hook_total integer, last_hook_at timestamp with time zone)
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    (SELECT count(*)::int FROM pg_proc p
       JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_module),
    (SELECT count(*)::int FROM pg_proc p
       JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_module || '_ut'),
    (SELECT count(*)::int FROM workbench.agent_message
      WHERE to_module = p_module AND status = 'new'),
    (SELECT count(*)::int FROM workbench.agent_message
      WHERE to_module = p_module OR from_module = p_module),
    (SELECT count(*)::int FROM workbench.hook_log
      WHERE module = p_module AND NOT allowed),
    (SELECT count(*)::int FROM workbench.hook_log
      WHERE module = p_module),
    (SELECT max(created_at) FROM workbench.hook_log
      WHERE module = p_module);
END;
$function$;
COMMENT ON FUNCTION ops._module_stats(text) IS 'Stats agrégées pour un module : fonctions, tests, messages, hooks';

CREATE OR REPLACE FUNCTION ops._recent_events(p_limit integer DEFAULT 20)
 RETURNS TABLE(event_type text, module text, detail text, created_at timestamp with time zone)
 LANGUAGE sql
 STABLE
AS $function$
  (
    SELECT 'message'::text,
           m.from_module || ' -> ' || m.to_module,
           m.msg_type || ': ' || m.subject,
           m.created_at
      FROM workbench.agent_message m
     ORDER BY m.created_at DESC
     LIMIT p_limit
  )
  UNION ALL
  (
    SELECT 'hook'::text,
           h.module,
           regexp_replace(h.tool, '^mcp__plpgsql-workbench__', '')
             || CASE WHEN h.action <> '' THEN ' — ' || left(h.action, 60) ELSE '' END
             || CASE WHEN h.allowed THEN '' ELSE ' [BLOCKED]' END,
           h.created_at
      FROM workbench.hook_log h
     ORDER BY h.created_at DESC
     LIMIT p_limit
  )
  ORDER BY created_at DESC
  LIMIT p_limit;
$function$;
COMMENT ON FUNCTION ops._recent_events(integer) IS 'Messages et hooks intercalés chronologiquement';

CREATE OR REPLACE FUNCTION ops.brand()
 RETURNS text
 LANGUAGE sql
 STABLE
AS $function$
  SELECT 'Ops'::text;
$function$;
COMMENT ON FUNCTION ops.brand() IS 'Brand name for ops module';

CREATE OR REPLACE FUNCTION ops.get_agent(p_module text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_stats record;
  v_msg_rows text[];
  v_hook_rows text[];
  r record;
  v_type_variant text;
  v_status_variant text;
BEGIN
  -- Breadcrumb
  v_body := pgv.breadcrumb(VARIADIC ARRAY['Dashboard', '/', p_module]);

  -- Stats
  SELECT * INTO v_stats FROM ops._module_stats(p_module);
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('Fonctions', v_stats.func_count::text),
    pgv.stat('Tests', v_stats.test_count::text),
    pgv.stat('Messages', v_stats.msg_new::text || ' / ' || v_stats.msg_total::text, 'new / total'),
    pgv.stat('Hooks bloques', v_stats.hook_deny::text || ' / ' || v_stats.hook_total::text)
  ]);

  -- Terminal container (auto-connects via x-init)
  v_body := v_body
    || '<div x-data="opsTerminal" data-module="' || pgv.esc(p_module) || '" x-init="$nextTick(() => connect())" class="ops-terminal ops-terminal--detail">'
    || '<div x-ref="terminal"></div>'
    || '<div x-show="!connected" class="ops-terminal-status">Connexion...</div>'
    || '</div>';

  -- Messages for this module (last 20)
  v_msg_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.id, m.from_module, m.to_module, m.msg_type, m.subject, m.status,
           to_char(m.created_at, 'DD/MM HH24:MI') AS dt
      FROM workbench.agent_message m
     WHERE m.from_module = p_module OR m.to_module = p_module
     ORDER BY m.created_at DESC
     LIMIT 20
  LOOP
    v_type_variant := CASE r.msg_type
      WHEN 'feature_request' THEN 'info'
      WHEN 'bug_report' THEN 'danger'
      WHEN 'issue_report' THEN 'danger'
      WHEN 'question' THEN 'warning'
      ELSE 'default'
    END;
    v_status_variant := CASE r.status
      WHEN 'new' THEN 'warning'
      WHEN 'acknowledged' THEN 'info'
      WHEN 'resolved' THEN 'success'
      ELSE 'default'
    END;
    v_msg_rows := v_msg_rows || ARRAY[
      pgv.badge(r.from_module, 'default'),
      pgv.badge(r.to_module, 'default'),
      pgv.badge(r.msg_type, v_type_variant),
      pgv.esc(r.subject),
      pgv.badge(r.status, v_status_variant),
      r.dt
    ];
  END LOOP;

  -- Hooks for this module (last 20)
  v_hook_rows := ARRAY[]::text[];
  FOR r IN
    SELECT regexp_replace(h.tool, '^mcp__plpgsql-workbench__', '') AS tool,
           left(h.action, 60) AS action,
           h.allowed,
           to_char(h.created_at, 'DD/MM HH24:MI') AS dt
      FROM workbench.hook_log h
     WHERE h.module = p_module
     ORDER BY h.created_at DESC
     LIMIT 20
  LOOP
    v_hook_rows := v_hook_rows || ARRAY[
      pgv.esc(r.tool),
      pgv.esc(r.action),
      CASE WHEN r.allowed THEN pgv.badge('✓', 'success') ELSE pgv.badge('✗', 'danger') END,
      r.dt
    ];
  END LOOP;

  -- Tabs: Messages + Hooks
  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    'Messages',
    CASE WHEN array_length(v_msg_rows, 1) IS NULL
      THEN pgv.empty('Aucun message')
      ELSE pgv.md_table(ARRAY['De', 'A', 'Type', 'Sujet', 'Status', 'Date'], v_msg_rows)
    END,
    'Hooks',
    CASE WHEN array_length(v_hook_rows, 1) IS NULL
      THEN pgv.empty('Aucun evenement hook')
      ELSE pgv.md_table(ARRAY['Tool', 'Action', 'OK', 'Date'], v_hook_rows)
    END
  ]);

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ops.get_agent(text) IS 'Agent detail page with auto-connecting terminal, messages and hooks';

CREATE OR REPLACE FUNCTION ops.get_agents()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN '<div x-data="opsTmuxGrid">'
    || '<template x-if="loading"><p>Chargement...</p></template>'
    || '<template x-if="!loading && sessions.length === 0">'
    || pgv.empty('Aucune session active', 'make agents pour lancer les agents.')
    || '</template>'
    || '<template x-if="!loading && sessions.length > 0">'
    || '<div>'
    || '<table role="grid">'
    || '<thead><tr><th>Agent</th><th>Status</th></tr></thead>'
    || '<tbody>'
    || '<template x-for="s in sessions" :key="s.name">'
    || '<tr @click="activateSession(s.name)" class="pgv-link" :class="{ ''ops-row-selected'': activeModule === s.name }">'
    || '<td><span class="ops-agent-dot" :class="{ connected: s._connected, disconnected: s._disconnected && !s._reconnecting, loading: s._reconnecting }"></span> <span x-text="s.name"></span></td>'
    || '<td><span class="pgv-badge" :class="s.status && s.status !== ''idle'' ? ''pgv-badge-success'' : ''pgv-badge-default''" x-text="s.status || ''idle''"></span></td>'
    || '</tr>'
    || '</template>'
    || '</tbody>'
    || '</table>'
    || '<template x-if="activeModule">'
    || pgv.card(
        '<span x-text="activeModule"></span>',
        '<div class="ops-agents-terminal">'
        || '<template x-for="s in sessions" :key="''term-'' + s.name">'
        || '<div x-show="activeModule === s.name">'
        || '<div :data-terminal-for="s.name" class="ops-terminal-body"></div>'
        || '</div>'
        || '</template>'
        || '</div>',
        NULL
      )
    || '</template>'
    || '</div>'
    || '</template>'
    || '</div>';
END;
$function$;
COMMENT ON FUNCTION ops.get_agents() IS 'Liste agents en table HTML + terminal dans une card scrollable';

CREATE OR REPLACE FUNCTION ops.get_dashboard()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  v_mod text;
  v_stats record;
  v_total_funcs int := 0;
  v_total_tests int := 0;
  v_total_pending int := 0;
  v_total_hook_deny int := 0;
  v_last_hook text;
BEGIN
  v_rows := ARRAY[]::text[];

  FOR v_mod IN SELECT module FROM ops._module_list()
  LOOP
    SELECT * INTO v_stats FROM ops._module_stats(v_mod);

    v_total_funcs := v_total_funcs + v_stats.func_count;
    v_total_tests := v_total_tests + v_stats.test_count;
    v_total_pending := v_total_pending + v_stats.msg_new;
    v_total_hook_deny := v_total_hook_deny + v_stats.hook_deny;

    v_last_hook := CASE
      WHEN v_stats.last_hook_at IS NOT NULL
        THEN to_char(v_stats.last_hook_at, 'DD/MM HH24:MI')
      ELSE '-'
    END;

    v_rows := v_rows || ARRAY[
      pgv.esc(v_mod),
      v_stats.func_count::text,
      v_stats.test_count::text,
      CASE WHEN v_stats.msg_new > 0
        THEN pgv.badge(v_stats.msg_new::text, 'warning')
        ELSE '0'
      END,
      CASE WHEN v_stats.hook_deny > 0
        THEN pgv.badge(v_stats.hook_deny::text, 'danger')
        ELSE '0'
      END || ' / ' || v_stats.hook_total::text,
      v_last_hook
    ];
  END LOOP;

  -- Top stats
  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Fonctions', v_total_funcs::text, 'tous modules'),
    pgv.stat('Tests', v_total_tests::text, 'pgTAP'),
    pgv.stat('Messages pending', v_total_pending::text),
    pgv.stat('Hooks bloques', v_total_hook_deny::text, 'total')
  ]);

  -- Module detail table
  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun module', 'Deployer des modules pour les voir ici.');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Module', 'Fonctions', 'Tests', 'Pending', 'Hooks deny', 'Dernier hook'],
      v_rows
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ops.get_dashboard() IS 'Vue globale santé modules — stats agrégées + tableau détaillé par module';

CREATE OR REPLACE FUNCTION ops.get_doc(p_params jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_topic text;
BEGIN
  v_topic := p_params->>'topic';
  IF v_topic IS NULL THEN
    RETURN pgv.empty('Topic manquant', 'Param topic requis');
  END IF;
  RETURN pgv.doc(v_topic);
END;
$function$;
COMMENT ON FUNCTION ops.get_doc(jsonb) IS 'Display a documentation topic via pgv.doc()';

CREATE OR REPLACE FUNCTION ops.get_docs()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_rows text := '';
  v_rec record;
  v_count int := 0;
BEGIN
  FOR v_rec IN
    SELECT topic, length(content) AS size FROM workbench.doc ORDER BY topic
  LOOP
    v_rows := v_rows
      || '| [' || pgv.esc(v_rec.topic) || '](/ops/doc?topic=' || pgv.esc(v_rec.topic) || ')'
      || ' | ' || pgv.filesize(v_rec.size) || ' |' || chr(10);
    v_count := v_count + 1;
  END LOOP;

  IF v_count = 0 THEN
    RETURN pgv.empty('Aucune documentation', 'workbench.doc est vide');
  END IF;

  RETURN '<md>' || chr(10)
    || '| Topic | Taille |' || chr(10)
    || '|-------|--------|' || chr(10)
    || v_rows
    || '</md>';
END;
$function$;
COMMENT ON FUNCTION ops.get_docs() IS 'List all documentation topics from workbench.doc';

CREATE OR REPLACE FUNCTION ops.get_hooks(p_module text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_rows text[];
  v_body text;
  r record;
BEGIN
  v_rows := ARRAY[]::text[];

  FOR r IN
    SELECT h.module,
           regexp_replace(h.tool, '^mcp__plpgsql-workbench__', '') AS tool,
           left(h.action, 60) AS action,
           h.allowed,
           COALESCE(left(h.reason, 60), '') AS reason,
           to_char(h.created_at, 'DD/MM HH24:MI') AS dt
      FROM workbench.hook_log h
     WHERE (p_module IS NULL OR h.module = p_module)
     ORDER BY h.created_at DESC
     LIMIT 100
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.badge(r.module, 'default'),
      pgv.esc(r.tool),
      pgv.esc(r.action),
      CASE WHEN r.allowed THEN pgv.badge('✓', 'success') ELSE pgv.badge('✗', 'danger') END,
      pgv.esc(r.reason),
      r.dt
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucun evenement hook', 'Les evenements hooks apparaitront ici.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Module', 'Tool', 'Action', 'OK', 'Raison', 'Date'],
      v_rows,
      20
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ops.get_hooks(text) IS 'Liste paginée des événements hooks, filtrable par module';

CREATE OR REPLACE FUNCTION ops.get_index()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_cards text[];
  v_timeline_rows text[];
  v_mod text;
  v_stats record;
  v_session_status text;
  v_active_count int;
  v_msg_new_total int;
  v_hook_deny_today int;
  v_module_count int;
  v_total_funcs int;
  v_total_tests int;
  v_resolved_tasks int;
  r record;
BEGIN
  -- Global stats
  SELECT count(*)::int INTO v_active_count
    FROM workbench.agent_session WHERE status = 'running';

  SELECT count(*)::int INTO v_msg_new_total
    FROM workbench.agent_message WHERE status = 'new';

  SELECT count(*)::int INTO v_hook_deny_today
    FROM workbench.hook_log
   WHERE NOT allowed AND created_at >= date_trunc('day', now());

  SELECT count(*)::int INTO v_module_count
    FROM ops._module_list();

  -- Total functions across all module schemas
  SELECT count(*)::int INTO v_total_funcs
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
   WHERE n.nspname IN (SELECT module FROM ops._module_list());

  -- Total tests across all _ut schemas
  SELECT count(*)::int INTO v_total_tests
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
   WHERE n.nspname IN (SELECT module || '_ut' FROM ops._module_list())
     AND p.proname LIKE 'test\_%' ESCAPE '\';

  -- Resolved tasks
  SELECT count(*)::int INTO v_resolved_tasks
    FROM workbench.agent_message
   WHERE status = 'resolved' AND msg_type = 'task';

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Modules', v_module_count::text),
    pgv.stat('Fonctions', v_total_funcs::text, 'tous modules'),
    pgv.stat('Tests', v_total_tests::text, 'pgTAP'),
    pgv.stat('Taches resolues', v_resolved_tasks::text)
  ]);

  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('Agents actifs', v_active_count::text),
    pgv.stat('Messages non lus', v_msg_new_total::text),
    pgv.stat('Hooks bloques', v_hook_deny_today::text, 'aujourd''hui')
  ]);

  -- Agent cards
  v_cards := ARRAY[]::text[];
  FOR v_mod IN SELECT module FROM ops._module_list()
  LOOP
    SELECT * INTO v_stats FROM ops._module_stats(v_mod);

    -- Check session status
    SELECT s.status INTO v_session_status
      FROM workbench.agent_session s
     WHERE s.module = v_mod AND s.status = 'running'
     ORDER BY s.started_at DESC LIMIT 1;

    v_cards := v_cards || pgv.card(
      '<a href="/' || pgv.esc(v_mod) || '/">' || pgv.esc(v_mod) || '</a> '
        || pgv.badge(
          COALESCE(v_session_status, 'idle'),
          CASE WHEN v_session_status = 'running' THEN 'success' ELSE 'default' END
        ),
      pgv.grid(VARIADIC ARRAY[
        pgv.stat('Fonctions', v_stats.func_count::text),
        pgv.stat('Tests', v_stats.test_count::text),
        pgv.stat('Messages', v_stats.msg_new::text, 'non lus'),
        pgv.stat('Hook deny', v_stats.hook_deny::text)
      ]),
      '<a href="' || pgv.call_ref('get_agent', jsonb_build_object('p_module', v_mod)) || '">Agent</a>'
        || ' · <a href="/' || pgv.esc(v_mod) || '/">Frontend</a>'
    );
  END LOOP;

  IF array_length(v_cards, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun module', 'Deployer des modules pour les voir ici.');
  ELSE
    v_body := v_body || '<div class="ops-agent-grid">' || array_to_string(v_cards, '') || '</div>';
  END IF;

  -- Recent events timeline
  v_timeline_rows := ARRAY[]::text[];
  FOR r IN SELECT * FROM ops._recent_events(20)
  LOOP
    v_timeline_rows := v_timeline_rows || ARRAY[
      pgv.badge(r.event_type, CASE r.event_type WHEN 'message' THEN 'info' ELSE 'warning' END),
      pgv.badge(r.module, 'default'),
      r.detail,
      to_char(r.created_at, 'DD/MM HH24:MI')
    ];
  END LOOP;

  IF array_length(v_timeline_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Activite recente</h3>'
      || pgv.md_table(
        ARRAY['Type', 'Module', 'Detail', 'Date'],
        v_timeline_rows
      );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ops.get_index() IS 'Dashboard principal — stats globales enrichies (fonctions, tests, tâches résolues), grille agents, timeline';

CREATE OR REPLACE FUNCTION ops.get_message(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_msg record;
  v_type_variant text;
  v_status_variant text;
  v_reply record;
  v_reply_rows text[];
BEGIN
  SELECT * INTO v_msg FROM workbench.agent_message WHERE id = p_id;

  IF v_msg IS NULL THEN
    RETURN pgv.empty('Message #' || p_id::text || ' introuvable');
  END IF;

  v_type_variant := CASE v_msg.msg_type
    WHEN 'feature_request' THEN 'info'
    WHEN 'bug_report' THEN 'danger'
    WHEN 'issue_report' THEN 'danger'
    WHEN 'question' THEN 'warning'
    WHEN 'task' THEN 'success'
    ELSE 'default'
  END;
  v_status_variant := CASE v_msg.status
    WHEN 'new' THEN 'danger'
    WHEN 'acknowledged' THEN 'warning'
    WHEN 'resolved' THEN 'success'
    ELSE 'default'
  END;

  -- Breadcrumb
  v_body := pgv.breadcrumb(VARIADIC ARRAY['Messages', '/ops/messages', '#' || p_id::text]);

  -- Header stats
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('De', v_msg.from_module),
    pgv.stat('A', v_msg.to_module),
    pgv.stat('Type', v_msg.msg_type),
    pgv.stat('Status', v_msg.status)
  ]);

  -- Subject + badges
  v_body := v_body || '<h3>' || pgv.esc(v_msg.subject) || ' '
    || pgv.badge(v_msg.msg_type, v_type_variant) || ' '
    || pgv.badge(v_msg.status, v_status_variant);

  IF v_msg.priority <> 'normal' THEN
    v_body := v_body || ' ' || pgv.badge(v_msg.priority, 'danger');
  END IF;

  v_body := v_body || '</h3>';

  -- Body
  IF v_msg.body IS NOT NULL THEN
    v_body := v_body || pgv.card('Contenu', '<pre>' || pgv.esc(v_msg.body) || '</pre>', NULL);
  END IF;

  -- Payload
  IF v_msg.payload IS NOT NULL THEN
    v_body := v_body || pgv.card('Payload', '<pre>' || pgv.esc(jsonb_pretty(v_msg.payload)) || '</pre>', NULL);
  END IF;

  -- Resolution
  IF v_msg.status = 'resolved' THEN
    v_body := v_body || pgv.card(
      'Resolution ' || pgv.badge('resolved', 'success'),
      '<pre>' || pgv.esc(COALESCE(v_msg.resolution, '-')) || '</pre>'
        || CASE WHEN v_msg.result IS NOT NULL
             THEN '<h4>Result</h4><pre>' || pgv.esc(jsonb_pretty(v_msg.result)) || '</pre>'
             ELSE ''
           END,
      CASE WHEN v_msg.resolved_at IS NOT NULL
        THEN 'Resolu le ' || to_char(v_msg.resolved_at, 'DD/MM/YYYY HH24:MI')
        ELSE NULL
      END
    );
  END IF;

  -- Reply chain (messages that reply to this one)
  v_reply_rows := ARRAY[]::text[];
  FOR v_reply IN
    SELECT m.id, m.from_module, m.to_module, m.msg_type, m.subject, m.status,
           to_char(m.created_at, 'DD/MM HH24:MI') AS dt
      FROM workbench.agent_message m
     WHERE m.reply_to = p_id
     ORDER BY m.created_at
  LOOP
    v_reply_rows := v_reply_rows || ARRAY[
      '<a href="' || pgv.call_ref('get_message', jsonb_build_object('p_id', v_reply.id)) || '">#' || v_reply.id::text || '</a>',
      pgv.badge(v_reply.from_module, 'default'),
      pgv.esc(v_reply.subject),
      pgv.badge(v_reply.status, CASE v_reply.status WHEN 'resolved' THEN 'success' WHEN 'new' THEN 'danger' ELSE 'warning' END),
      v_reply.dt
    ];
  END LOOP;

  IF array_length(v_reply_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h4>Reponses</h4>'
      || pgv.md_table(ARRAY['#', 'De', 'Sujet', 'Status', 'Date'], v_reply_rows);
  END IF;

  -- Parent link
  IF v_msg.reply_to IS NOT NULL THEN
    v_body := v_body || '<p>En reponse a <a href="'
      || pgv.call_ref('get_message', jsonb_build_object('p_id', v_msg.reply_to))
      || '">#' || v_msg.reply_to::text || '</a></p>';
  END IF;

  -- Timestamps
  v_body := v_body || '<p class="ops-timestamps">'
    || 'Cree: ' || to_char(v_msg.created_at, 'DD/MM/YYYY HH24:MI')
    || CASE WHEN v_msg.acknowledged_at IS NOT NULL
         THEN ' · Ack: ' || to_char(v_msg.acknowledged_at, 'DD/MM/YYYY HH24:MI')
         ELSE ''
       END
    || CASE WHEN v_msg.resolved_at IS NOT NULL
         THEN ' · Resolu: ' || to_char(v_msg.resolved_at, 'DD/MM/YYYY HH24:MI')
         ELSE ''
       END
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ops.get_message(integer) IS 'Detail d un message inter-agents avec body, payload, resolution et fil de discussion';

CREATE OR REPLACE FUNCTION ops.get_messages(p_module text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rows text[];
  v_body text;
  r record;
  v_type_variant text;
  v_status_variant text;
BEGIN
  v_rows := ARRAY[]::text[];

  FOR r IN
    SELECT m.id, m.from_module, m.to_module, m.msg_type, m.subject, m.status,
           to_char(m.created_at, 'DD/MM HH24:MI') AS dt
      FROM workbench.agent_message m
     WHERE (p_module IS NULL OR m.from_module = p_module OR m.to_module = p_module)
     ORDER BY m.created_at DESC
     LIMIT 100
  LOOP
    v_type_variant := CASE r.msg_type
      WHEN 'feature_request' THEN 'info'
      WHEN 'bug_report' THEN 'danger'
      WHEN 'issue_report' THEN 'danger'
      WHEN 'question' THEN 'warning'
      WHEN 'task' THEN 'success'
      ELSE 'default'
    END;
    v_status_variant := CASE r.status
      WHEN 'new' THEN 'danger'
      WHEN 'acknowledged' THEN 'warning'
      WHEN 'resolved' THEN 'success'
      ELSE 'default'
    END;

    v_rows := v_rows || ARRAY[
      '<a href="' || pgv.call_ref('get_message', jsonb_build_object('p_id', r.id)) || '">#' || r.id::text || '</a>',
      pgv.badge(r.from_module, 'default'),
      pgv.badge(r.to_module, 'default'),
      pgv.badge(r.msg_type, v_type_variant),
      pgv.esc(left(r.subject, 60)),
      pgv.badge(r.status, v_status_variant),
      r.dt
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucun message', 'Les messages inter-agents apparaitront ici.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['#', 'De', 'A', 'Type', 'Sujet', 'Status', 'Date'],
      v_rows,
      20
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ops.get_messages(text) IS 'Liste paginée des messages inter-agents, filtrable par module, avec lien détail';

CREATE OR REPLACE FUNCTION ops.get_modules()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  v_mod text;
  v_stats record;
  v_first_seen timestamptz;
  v_is_new boolean;
  v_total_funcs int := 0;
  v_total_tests int := 0;
  v_module_count int := 0;
BEGIN
  v_rows := ARRAY[]::text[];

  FOR v_mod IN SELECT module FROM ops._module_list()
  LOOP
    SELECT * INTO v_stats FROM ops._module_stats(v_mod);
    v_module_count := v_module_count + 1;
    v_total_funcs := v_total_funcs + v_stats.func_count;
    v_total_tests := v_total_tests + v_stats.test_count;

    -- Detect "new" modules: first activity within 7 days or no activity at all
    SELECT LEAST(
      (SELECT min(created_at) FROM workbench.agent_message
       WHERE to_module = v_mod OR from_module = v_mod),
      (SELECT min(created_at) FROM workbench.hook_log WHERE module = v_mod)
    ) INTO v_first_seen;

    v_is_new := v_first_seen IS NULL OR v_first_seen > now() - interval '7 days';

    v_rows := v_rows || ARRAY[
      '<a href="/' || pgv.esc(v_mod) || '/">' || pgv.esc(v_mod) || '</a>'
        || CASE WHEN v_is_new THEN ' ' || pgv.badge('nouveau', 'success') ELSE '' END,
      v_stats.func_count::text,
      v_stats.test_count::text,
      v_stats.msg_total::text,
      CASE WHEN v_stats.last_hook_at IS NOT NULL
        THEN to_char(v_stats.last_hook_at, 'DD/MM HH24:MI')
        ELSE '-'
      END
    ];
  END LOOP;

  IF v_module_count = 0 THEN
    RETURN pgv.empty('Aucun module', 'Deployer des modules pour les voir ici.');
  END IF;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Modules', v_module_count::text),
    pgv.stat('Fonctions', v_total_funcs::text, 'tous modules'),
    pgv.stat('Tests', v_total_tests::text, 'pgTAP')
  ]);

  v_body := v_body || pgv.md_table(
    ARRAY['Module', 'Fonctions', 'Tests', 'Messages', 'Derniere activite'],
    v_rows
  );

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ops.get_modules() IS 'Liste tous les modules avec stats (fonctions, tests, messages, activité), badge nouveau pour modules récents';

CREATE OR REPLACE FUNCTION ops.get_tests(p_schema text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  v_total_tests int := 0;
  v_total_schemas int := 0;
  v_last_passed int := 0;
  v_last_failed int := 0;
  r record;
  v_run record;
  v_history_rows text[];
BEGIN
  v_rows := ARRAY[]::text[];

  -- List all _ut schemas with test counts
  FOR r IN
    SELECT n.nspname AS schema_ut,
           count(*)::int AS test_count
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
     WHERE n.nspname LIKE '%\_ut' ESCAPE '\'
       AND p.proname LIKE 'test\_%' ESCAPE '\'
       AND (p_schema IS NULL OR n.nspname = p_schema || '_ut' OR n.nspname = p_schema)
     GROUP BY n.nspname
     ORDER BY n.nspname
  LOOP
    v_total_schemas := v_total_schemas + 1;
    v_total_tests := v_total_tests + r.test_count;

    -- Last run for this schema
    SELECT * INTO v_run
      FROM workbench.test_run
     WHERE schema_ut = r.schema_ut
     ORDER BY run_at DESC LIMIT 1;

    v_rows := v_rows || ARRAY[
      pgv.esc(r.schema_ut),
      r.test_count::text,
      CASE WHEN v_run.id IS NOT NULL
        THEN pgv.badge(v_run.passed::text, 'success') || ' / '
          || CASE WHEN v_run.failed > 0
               THEN pgv.badge(v_run.failed::text, 'danger')
               ELSE '0'
             END
        ELSE '-'
      END,
      CASE WHEN v_run.id IS NOT NULL
        THEN v_run.duration_ms || ' ms'
        ELSE '-'
      END,
      CASE WHEN v_run.id IS NOT NULL
        THEN to_char(v_run.run_at, 'DD/MM HH24:MI')
        ELSE '-'
      END,
      pgv.action('post_test_run', 'Lancer',
        jsonb_build_object('p_schema', r.schema_ut),
        'Lancer les tests ' || r.schema_ut || ' ?')
    ];

    IF v_run.id IS NOT NULL THEN
      v_last_passed := v_last_passed + v_run.passed;
      v_last_failed := v_last_failed + v_run.failed;
    END IF;
  END LOOP;

  IF v_total_schemas = 0 THEN
    RETURN pgv.empty('Aucun test', 'Aucun schema _ut trouve.');
  END IF;

  -- Summary stats
  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Schemas', v_total_schemas::text),
    pgv.stat('Tests', v_total_tests::text, 'fonctions test_*'),
    pgv.stat('Derniers OK', v_last_passed::text, 'passed'),
    pgv.stat('Derniers KO', v_last_failed::text, 'failed')
  ]);

  v_body := v_body || pgv.md_table(
    ARRAY['Schema', 'Tests', 'Resultat', 'Duree', 'Dernier run', 'Action'],
    v_rows
  );

  -- Recent run history (last 10)
  v_history_rows := ARRAY[]::text[];
  FOR v_run IN
    SELECT * FROM workbench.test_run
     ORDER BY run_at DESC LIMIT 10
  LOOP
    v_history_rows := v_history_rows || ARRAY[
      pgv.esc(v_run.schema_ut),
      pgv.badge(v_run.passed::text, 'success') || ' / '
        || CASE WHEN v_run.failed > 0
             THEN pgv.badge(v_run.failed::text, 'danger')
             ELSE '0'
           END,
      v_run.duration_ms || ' ms',
      to_char(v_run.run_at, 'DD/MM HH24:MI:SS')
    ];
  END LOOP;

  IF array_length(v_history_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Historique</h3>'
      || pgv.md_table(
        ARRAY['Schema', 'Resultat', 'Duree', 'Date'],
        v_history_rows
      );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ops.get_tests(text) IS 'Page historique tests pgTAP — liste schemas _ut avec stats, derniers runs, bouton lancer';

CREATE OR REPLACE FUNCTION ops.get_tool(p_name text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_exists boolean;
  v_pack text;
  v_rows text[];
  v_total_calls int;
  v_total_blocked int;
  v_mcp_name text;
  r record;
BEGIN
  -- Check existence
  SELECT EXISTS(SELECT 1 FROM workbench.toolbox_tool WHERE tool_name = p_name) INTO v_exists;
  IF NOT v_exists THEN
    RETURN pgv.empty('Tool "' || pgv.esc(p_name) || '" introuvable');
  END IF;

  -- Pack
  v_pack := CASE
    WHEN p_name LIKE 'pg\_%' ESCAPE '\' THEN 'plpgsql'
    WHEN p_name LIKE 'fs\_%' ESCAPE '\' THEN 'docstore'
    WHEN p_name LIKE 'gmail\_%' ESCAPE '\' THEN 'google'
    WHEN p_name LIKE 'doc\_%' ESCAPE '\' THEN 'docman'
    WHEN p_name LIKE 'ws\_%' ESCAPE '\' THEN 'plpgsql'
    ELSE 'other'
  END;

  v_mcp_name := 'mcp__plpgsql-workbench__' || p_name;

  -- Global stats for this tool
  SELECT count(*)::int, count(*) FILTER (WHERE NOT allowed)::int
    INTO v_total_calls, v_total_blocked
    FROM workbench.hook_log
   WHERE tool = v_mcp_name;

  -- Breadcrumb
  v_body := pgv.breadcrumb(VARIADIC ARRAY['Tools', '/ops/tools', pgv.esc(p_name)]);

  -- Header
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('Pack', v_pack),
    pgv.stat('Appels', v_total_calls::text, 'total traces'),
    pgv.stat('Bloques', v_total_blocked::text, 'par hooks')
  ]);

  -- Usage by module
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT module,
           count(*)::int AS calls,
           count(*) FILTER (WHERE allowed)::int AS allowed,
           count(*) FILTER (WHERE NOT allowed)::int AS blocked,
           max(created_at) AS last_used
      FROM workbench.hook_log
     WHERE tool = v_mcp_name
     GROUP BY module
     ORDER BY count(*) DESC
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.badge(r.module, 'default'),
      r.calls::text,
      r.allowed::text,
      CASE WHEN r.blocked > 0
        THEN pgv.badge(r.blocked::text, 'danger')
        ELSE '0'
      END,
      to_char(r.last_used, 'DD/MM HH24:MI')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Utilisation par module</h3>'
      || pgv.md_table(
        ARRAY['Module', 'Appels', 'OK', 'Bloques', 'Dernier'],
        v_rows
      );
  ELSE
    v_body := v_body || pgv.empty('Aucun appel trace', 'Ce tool n''a pas encore ete utilise via les hooks.');
  END IF;

  -- Recent calls (last 20)
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT module, action, allowed, reason, created_at
      FROM workbench.hook_log
     WHERE tool = v_mcp_name
     ORDER BY created_at DESC
     LIMIT 20
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.badge(r.module, 'default'),
      COALESCE(pgv.esc(r.action), '-'),
      CASE WHEN r.allowed
        THEN pgv.badge('OK', 'success')
        ELSE pgv.badge('BLOQUE', 'danger')
      END,
      COALESCE(pgv.esc(left(r.reason, 60)), '-'),
      to_char(r.created_at, 'DD/MM HH24:MI')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Appels recents</h3>'
      || pgv.md_table(
        ARRAY['Module', 'Action', 'Status', 'Raison', 'Date'],
        v_rows
      );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ops.get_tool(text) IS 'Detail d un MCP tool avec stats d utilisation par module et historique recent';

CREATE OR REPLACE FUNCTION ops.get_tools()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  v_total int;
  v_packs int;
  v_total_calls int;
  v_total_blocked int;
  r record;
BEGIN
  -- Stats globales
  SELECT count(*)::int INTO v_total FROM workbench.toolbox_tool;
  SELECT count(DISTINCT
    CASE
      WHEN tool_name LIKE 'pg\_%' ESCAPE '\' THEN 'plpgsql'
      WHEN tool_name LIKE 'fs\_%' ESCAPE '\' THEN 'docstore'
      WHEN tool_name LIKE 'gmail\_%' ESCAPE '\' THEN 'google'
      WHEN tool_name LIKE 'doc\_%' ESCAPE '\' THEN 'docman'
      WHEN tool_name LIKE 'ws\_%' ESCAPE '\' THEN 'plpgsql'
      ELSE 'other'
    END
  )::int INTO v_packs FROM workbench.toolbox_tool;

  SELECT count(*)::int, count(*) FILTER (WHERE NOT allowed)::int
    INTO v_total_calls, v_total_blocked
    FROM workbench.hook_log;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Tools', v_total::text),
    pgv.stat('Packs', v_packs::text),
    pgv.stat('Appels traces', v_total_calls::text, 'hook_log'),
    pgv.stat('Bloques', v_total_blocked::text, 'par hooks')
  ]);

  -- Table des tools avec stats
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT t.tool_name,
           CASE
             WHEN t.tool_name LIKE 'pg\_%' ESCAPE '\' THEN 'plpgsql'
             WHEN t.tool_name LIKE 'fs\_%' ESCAPE '\' THEN 'docstore'
             WHEN t.tool_name LIKE 'gmail\_%' ESCAPE '\' THEN 'google'
             WHEN t.tool_name LIKE 'doc\_%' ESCAPE '\' THEN 'docman'
             WHEN t.tool_name LIKE 'ws\_%' ESCAPE '\' THEN 'plpgsql'
             ELSE 'other'
           END AS pack,
           COALESCE(h.call_count, 0)::int AS calls,
           COALESCE(h.blocked, 0)::int AS blocked
      FROM workbench.toolbox_tool t
      LEFT JOIN (
        SELECT replace(tool, 'mcp__plpgsql-workbench__', '') AS tool_short,
               count(*)::int AS call_count,
               count(*) FILTER (WHERE NOT allowed)::int AS blocked
          FROM workbench.hook_log
         GROUP BY tool_short
      ) h ON h.tool_short = t.tool_name
     ORDER BY
       CASE
         WHEN t.tool_name LIKE 'pg\_%' ESCAPE '\' THEN 1
         WHEN t.tool_name LIKE 'ws\_%' ESCAPE '\' THEN 1
         WHEN t.tool_name LIKE 'fs\_%' ESCAPE '\' THEN 2
         WHEN t.tool_name LIKE 'gmail\_%' ESCAPE '\' THEN 3
         WHEN t.tool_name LIKE 'doc\_%' ESCAPE '\' THEN 4
         ELSE 5
       END,
       t.tool_name
  LOOP
    v_rows := v_rows || ARRAY[
      '<a href="/ops/tool?p_name=' || pgv.esc(r.tool_name) || '">' || pgv.esc(r.tool_name) || '</a>',
      pgv.badge(r.pack, CASE r.pack
        WHEN 'plpgsql' THEN 'success'
        WHEN 'docstore' THEN 'info'
        WHEN 'google' THEN 'warning'
        WHEN 'docman' THEN 'default'
        ELSE 'default'
      END),
      r.calls::text,
      CASE WHEN r.blocked > 0
        THEN pgv.badge(r.blocked::text, 'danger')
        ELSE '0'
      END
    ];
  END LOOP;

  v_body := v_body || pgv.md_table(
    ARRAY['Tool', 'Pack', 'Appels', 'Bloques'],
    v_rows
  );

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ops.get_tools() IS 'Liste tous les MCP tools groupes par pack avec stats d utilisation depuis hook_log';

