CREATE OR REPLACE FUNCTION ops.post_test_run(p_schema text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_start timestamptz;
  v_duration_ms int;
  v_passed int := 0;
  v_failed int := 0;
  v_total int := 0;
  v_line text;
BEGIN
  IF p_schema IS NULL OR p_schema = '' THEN
    RETURN pgv.toast('Schema requis', 'error');
  END IF;

  -- Verify schema exists
  IF NOT EXISTS(SELECT 1 FROM pg_namespace WHERE nspname = p_schema) THEN
    RETURN pgv.toast('Schema ' || pgv.esc(p_schema) || ' introuvable', 'error');
  END IF;

  v_start := clock_timestamp();

  -- Run pgTAP tests
  FOR v_line IN SELECT * FROM runtests(p_schema::name, ''::text)
  LOOP
    IF v_line LIKE 'ok %' THEN
      v_passed := v_passed + 1;
      v_total := v_total + 1;
    ELSIF v_line LIKE 'not ok %' THEN
      v_failed := v_failed + 1;
      v_total := v_total + 1;
    END IF;
  END LOOP;

  v_duration_ms := extract(millisecond FROM clock_timestamp() - v_start)::int
                 + extract(second FROM clock_timestamp() - v_start)::int * 1000;

  -- Record run
  INSERT INTO workbench.test_run (schema_ut, total, passed, failed, duration_ms)
  VALUES (p_schema, v_total, v_passed, v_failed, v_duration_ms);

  IF v_failed > 0 THEN
    RETURN pgv.toast(pgv.esc(p_schema) || ' : ' || v_passed || ' OK, ' || v_failed || ' KO (' || v_duration_ms || ' ms)', 'error');
  END IF;

  RETURN pgv.toast(pgv.esc(p_schema) || ' : ' || v_passed || '/' || v_total || ' OK (' || v_duration_ms || ' ms)', 'success');
END;
$function$;
COMMENT ON FUNCTION ops.post_test_run(text) IS 'Lance les tests pgTAP pour un schema _ut, enregistre le résultat dans workbench.test_run';

GRANT USAGE ON SCHEMA ops TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA ops TO web_anon;

-- Schema: ops_ut
CREATE SCHEMA IF NOT EXISTS ops_ut;

CREATE OR REPLACE FUNCTION ops_ut.test_filtered_views()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- get_messages with filter
  v_html := ops.get_messages('cad');
  RETURN NEXT ok(v_html IS NOT NULL, 'get_messages(cad) returns HTML');

  -- get_messages with non-existent module -> empty state
  v_html := ops.get_messages('nonexistent_xyz');
  RETURN NEXT ok(v_html LIKE '%pgv-empty%', 'get_messages(nonexistent) shows empty state');

  -- get_hooks with filter
  v_html := ops.get_hooks('cad');
  RETURN NEXT ok(v_html IS NOT NULL, 'get_hooks(cad) returns HTML');

  -- get_hooks with non-existent module -> empty state
  v_html := ops.get_hooks('nonexistent_xyz');
  RETURN NEXT ok(v_html LIKE '%pgv-empty%', 'get_hooks(nonexistent) shows empty state');

  -- get_agent with non-existent module -> still renders (stats will be 0)
  v_html := ops.get_agent('nonexistent_xyz');
  RETURN NEXT ok(v_html IS NOT NULL, 'get_agent(nonexistent) renders without error');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_agent(nonexistent) still shows stat widgets');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_filtered_views() IS 'Test get_messages and get_hooks with module filter and edge cases';

CREATE OR REPLACE FUNCTION ops_ut.test_get_agents()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_agents();
  RETURN NEXT ok(v_html IS NOT NULL AND length(v_html) > 0, 'get_agents renders HTML');
  RETURN NEXT ok(v_html LIKE '%opsTmuxGrid%', 'get_agents uses opsTmuxGrid component');
  RETURN NEXT ok(v_html LIKE '%<table%', 'get_agents has table');
  RETURN NEXT ok(v_html LIKE '%activateSession%', 'get_agents has activateSession click handler');
  RETURN NEXT ok(v_html LIKE '%data-terminal-for%', 'get_agents has terminal container');
  RETURN NEXT ok(v_html LIKE '%ops-agent-dot%', 'get_agents has connection status dot');
  RETURN NEXT ok(v_html LIKE '%pgv-badge%', 'get_agents has status badge');
  RETURN NEXT ok(v_html LIKE '%pgv-empty%', 'get_agents has empty state fallback');
  RETURN NEXT ok(v_html NOT LIKE '%style="%', 'get_agents has no inline styles');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_get_agents() IS 'Test get_agents — table HTML + card terminal';

CREATE OR REPLACE FUNCTION ops_ut.test_get_dashboard()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_dashboard();
  RETURN NEXT ok(v_html IS NOT NULL AND length(v_html) > 0, 'get_dashboard renders HTML');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_dashboard contains stat widgets');
  RETURN NEXT ok(v_html LIKE '%Fonctions%', 'get_dashboard shows total functions');
  RETURN NEXT ok(v_html LIKE '%Tests%', 'get_dashboard shows total tests');
  RETURN NEXT ok(v_html LIKE '%cad%', 'get_dashboard lists cad module');
  -- No inline styles
  RETURN NEXT ok(v_html NOT LIKE '%style="%', 'get_dashboard has no inline styles');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_get_dashboard() IS 'Test get_dashboard renders health overview with stats and module table';

CREATE OR REPLACE FUNCTION ops_ut.test_get_message()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_id int;
BEGIN
  -- Get a real message id
  SELECT id INTO v_id FROM workbench.agent_message ORDER BY created_at DESC LIMIT 1;

  IF v_id IS NOT NULL THEN
    v_html := ops.get_message(v_id);
    RETURN NEXT ok(v_html IS NOT NULL AND length(v_html) > 0, 'get_message renders HTML for existing msg');
    RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_message shows stat widgets');
    RETURN NEXT ok(v_html LIKE '%breadcrumb%' OR v_html LIKE '%Messages%', 'get_message has breadcrumb');
    RETURN NEXT ok(v_html NOT LIKE '%style="%', 'get_message has no inline styles');
  ELSE
    RETURN NEXT ok(true, 'no messages in DB — skip detail test');
  END IF;

  -- Not found
  v_html := ops.get_message(-999);
  RETURN NEXT ok(v_html LIKE '%pgv-empty%', 'get_message(-999) shows empty state');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_get_message() IS 'Test get_message detail page — existing message and not found';

CREATE OR REPLACE FUNCTION ops_ut.test_get_modules()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_modules();
  RETURN NEXT ok(v_html IS NOT NULL AND length(v_html) > 0, 'get_modules renders HTML');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_modules contains stat widgets');
  RETURN NEXT ok(v_html LIKE '%Modules%', 'get_modules shows module count');
  RETURN NEXT ok(v_html LIKE '%Fonctions%', 'get_modules shows function count');
  RETURN NEXT ok(v_html LIKE '%Tests%', 'get_modules shows test count');
  RETURN NEXT ok(v_html LIKE '%cad%', 'get_modules lists cad module');
  RETURN NEXT ok(v_html LIKE '%crm%', 'get_modules lists crm module');
  -- No inline styles
  RETURN NEXT ok(v_html NOT LIKE '%style="%', 'get_modules has no inline styles');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_get_modules() IS 'Test get_modules affiche la registry avec stats et badge nouveau';

CREATE OR REPLACE FUNCTION ops_ut.test_get_tests()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- Full page (all schemas)
  v_html := ops.get_tests();
  RETURN NEXT ok(v_html IS NOT NULL AND length(v_html) > 0, 'get_tests renders HTML');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_tests contains stat widgets');
  RETURN NEXT ok(v_html LIKE '%Schemas%', 'get_tests shows schema count');
  RETURN NEXT ok(v_html LIKE '%cad_ut%', 'get_tests lists cad_ut');
  RETURN NEXT ok(v_html LIKE '%ops_ut%', 'get_tests lists ops_ut');
  RETURN NEXT ok(v_html LIKE '%Lancer%', 'get_tests has run buttons');
  RETURN NEXT ok(v_html NOT LIKE '%style="%', 'get_tests has no inline styles');

  -- Filtered by schema
  v_html := ops.get_tests('ops');
  RETURN NEXT ok(v_html LIKE '%ops_ut%', 'get_tests(ops) lists ops_ut');
  RETURN NEXT ok(v_html NOT LIKE '%cad_ut%', 'get_tests(ops) does not list cad_ut');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_get_tests() IS 'Test get_tests affiche les schemas _ut avec stats et boutons lancer';

CREATE OR REPLACE FUNCTION ops_ut.test_get_tool()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_tool('pg_query');

  RETURN NEXT ok(v_html IS NOT NULL, 'get_tool returns HTML');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'has stat widgets');
  RETURN NEXT ok(v_html LIKE '%plpgsql%', 'shows pack name');
  RETURN NEXT ok(v_html LIKE '%/ops/tools%', 'breadcrumb links to tools list');
  RETURN NEXT ok(v_html NOT LIKE '%style="%', 'no inline styles');

  -- Unknown tool
  v_html := ops.get_tool('nonexistent_tool');
  RETURN NEXT ok(v_html LIKE '%introuvable%', 'unknown tool shows empty state');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_get_tool() IS 'Test de la page get_tool — detail d un MCP tool';

CREATE OR REPLACE FUNCTION ops_ut.test_get_tools()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_tools();

  RETURN NEXT ok(v_html IS NOT NULL, 'get_tools returns HTML');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'has stat widgets');
  RETURN NEXT ok(v_html LIKE '%pg_query%', 'lists pg_query tool');
  RETURN NEXT ok(v_html LIKE '%pg_func_set%', 'lists pg_func_set tool');
  RETURN NEXT ok(v_html LIKE '%/ops/tool?p_name=%', 'has detail links');
  RETURN NEXT ok(v_html NOT LIKE '%style="%', 'no inline styles');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_get_tools() IS 'Test de la page get_tools — liste MCP tools';

CREATE OR REPLACE FUNCTION ops_ut.test_module_list()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_index();
  RETURN NEXT ok(length(v_html) > 100, 'get_index returns substantial HTML (uses _module_list)');
  RETURN NEXT ok(v_html LIKE '%cad%', 'get_index contains cad module card');
  -- New global stats
  RETURN NEXT ok(v_html LIKE '%Fonctions%', 'get_index shows total functions');
  RETURN NEXT ok(v_html LIKE '%Tests%', 'get_index shows total tests');
  RETURN NEXT ok(v_html LIKE '%Taches resolues%', 'get_index shows resolved tasks');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_module_list() IS 'Test _module_list et stats globales sur get_index';

CREATE OR REPLACE FUNCTION ops_ut.test_module_stats()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_agent('cad');
  RETURN NEXT ok(v_html IS NOT NULL, 'get_agent(cad) returns HTML');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_agent contains stat widgets');
  RETURN NEXT ok(v_html LIKE '%Fonctions%', 'get_agent shows function count');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_module_stats() IS 'Test _module_stats via get_agent qui l''utilise';

CREATE OR REPLACE FUNCTION ops_ut.test_pages_render()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT ok(length(ops.get_index()) > 0, 'get_index renders HTML');
  RETURN NEXT ok(length(ops.get_modules()) > 0, 'get_modules renders HTML');
  RETURN NEXT ok(length(ops.get_tests()) > 0, 'get_tests renders HTML');
  RETURN NEXT ok(length(ops.get_messages()) > 0, 'get_messages renders HTML');
  RETURN NEXT ok(length(ops.get_hooks()) > 0, 'get_hooks renders HTML');
  RETURN NEXT ok(length(ops.get_tools()) > 0, 'get_tools renders HTML');
  RETURN NEXT ok(length(ops.get_tool('pg_query')) > 0, 'get_tool renders HTML');
  RETURN NEXT ok(length(ops.get_agent('cad')) > 0, 'get_agent renders HTML');

  -- Navigation
  RETURN NEXT ok(ops.brand() = 'Ops', 'brand returns Ops');
  RETURN NEXT ok(
    (ops.nav_items())::text LIKE '%Dashboard%',
    'nav_items contains Dashboard'
  );
  RETURN NEXT ok(
    (ops.nav_items())::text LIKE '%Modules%',
    'nav_items contains Modules'
  );
  RETURN NEXT ok(
    (ops.nav_items())::text LIKE '%Tests%',
    'nav_items contains Tests'
  );
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_pages_render() IS 'Test toutes les pages retournent du HTML non-vide';

CREATE OR REPLACE FUNCTION ops_ut.test_recent_events()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- The dashboard shows recent events from hook_log and agent_message
  -- We have hook events from this session already
  v_html := ops.get_index();
  RETURN NEXT ok(v_html LIKE '%Activite recente%', 'get_index shows recent events section');
  RETURN NEXT ok(v_html LIKE '%hook%' OR v_html LIKE '%message%', 'timeline contains event badges');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_recent_events() IS 'Test _recent_events via le dashboard qui affiche la timeline';

